"""Extract labeled PROEIS captcha screenshots from a 2captcha uploads PDF."""

from __future__ import annotations

import json
import re
from pathlib import Path

import fitz
from PIL import Image


ROOT = Path(__file__).resolve().parents[2]
DESKTOP = Path.home() / "Desktop"
OUT_DIR = ROOT / "tests" / "proeis" / "pdf_2captcha_labeled"
PAGE_RENDER_SCALE = 1.5

# Coordinates measured from the rendered 1.5x PDF pages generated by Chrome.
CAPTCHA_BOXES = [
    (78, 92, 321, 202),
    (78, 632, 321, 743),
]


def find_pdf() -> Path:
    matches = sorted(DESKTOP.glob("*captchas enviados.pdf"))
    if not matches:
        raise FileNotFoundError("PDF '*captchas enviados.pdf' não encontrado no Desktop")
    return matches[-1]


def labels_from_text(text: str) -> list[str]:
    labels: list[str] = []
    lines = [line.strip() for line in text.splitlines()]
    for idx, line in enumerate(lines):
        if line != "}":
            continue
        for candidate in lines[idx + 1 : idx + 5]:
            clean = candidate.upper().replace(" ", "")
            if re.fullmatch(r"[A-Z0-9]{5,6}", clean):
                labels.append(clean)
                break
    return labels[-2:]


def main() -> int:
    pdf_path = find_pdf()
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    doc = fitz.open(str(pdf_path))
    rows = []
    for page_index in range(1, min(doc.page_count, 21)):
        page = doc[page_index]
        labels = labels_from_text(page.get_text())
        if not labels:
            continue
        pix = page.get_pixmap(matrix=fitz.Matrix(PAGE_RENDER_SCALE, PAGE_RENDER_SCALE), alpha=False)
        rendered = OUT_DIR / f"_page_{page_index + 1:02d}.png"
        pix.save(rendered)
        img = Image.open(rendered).convert("RGB")
        for item_index, label in enumerate(labels[:2]):
            if item_index >= len(CAPTCHA_BOXES):
                continue
            crop = img.crop(CAPTCHA_BOXES[item_index])
            filename = f"pdf_p{page_index + 1:02d}_{item_index + 1}_{label}.png"
            out_path = OUT_DIR / filename
            crop.save(out_path)
            rows.append(
                {
                    "page": page_index + 1,
                    "slot": item_index + 1,
                    "label": label,
                    "file": str(out_path),
                }
            )
    manifest = {
        "source_pdf": str(pdf_path),
        "count": len(rows),
        "labels": rows,
    }
    (OUT_DIR / "manifest.json").write_text(json.dumps(manifest, ensure_ascii=False, indent=2), encoding="utf-8")
    print(json.dumps({"out": str(OUT_DIR), "count": len(rows)}, ensure_ascii=False, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
